"use strict";(self.webpackChunkheiman_wiki_public=self.webpackChunkheiman_wiki_public||[]).push([["1702"],{2674(i){i.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"welcome","metadata":{"permalink":"/heiman-wiki-public/it/blog/welcome","source":"@site/i18n/it/docusaurus-plugin-content-blog/2021-08-26-welcome/index.mdx","title":"Benvenuti nel Wiki di Heiman Technology","description":"Benvenuti nel Wiki di Heiman Technology! Questa \xe8 la base di conoscenza ufficiale, che raccoglie documentazione sui prodotti, soluzioni tecniche, notizie del settore e aggiornamenti aziendali.","date":"2021-08-26T00:00:00.000Z","tags":[{"inline":false,"label":"Heiman Technology","permalink":"/heiman-wiki-public/it/blog/tags/heiman","description":"Notizie e aggiornamenti Heiman Technology"}],"readingTime":0.67,"hasTruncateMarker":true,"authors":[{"name":"Heiman Technology","title":"Shenzhen Heiman Technology Co., Ltd.","url":"https://www.heiman.com.cn","page":{"permalink":"/heiman-wiki-public/it/blog/authors/heiman"},"socials":{"x":"https://x.com/heimantech","linkedin":"https://www.linkedin.com/in/heimantech/"},"imageURL":"https://www.heiman.com.cn/favicon.ico","key":"heiman"}],"frontMatter":{"slug":"welcome","title":"Benvenuti nel Wiki di Heiman Technology","authors":["heiman"],"tags":["heiman"]},"unlisted":false,"nextItem":{"title":"Rivelatore di Fumo Intelligente Heiman con Protocollo Matter Ufficialmente Lanciato","permalink":"/heiman-wiki-public/it/blog/mdx-blog-post"}},"content":"Benvenuti nel Wiki di Heiman Technology! Questa \xe8 la base di conoscenza ufficiale, che raccoglie documentazione sui prodotti, soluzioni tecniche, notizie del settore e aggiornamenti aziendali.\\n\\n{/* truncate */}\\n\\n## Riguardo Questo Sito\\n\\nIl Wiki di Heiman Technology \xe8 dedicato a fornire una risorsa tecnica completa per partner, sviluppatori e clienti:\\n\\n- **Prodotti** \u2014 Antincendio Intelligente, Sicurezza Gas Intelligente, Assistenza Anziani Intelligente, Sensori Intelligenti\\n- **Soluzioni** \u2014 Soluzioni di sicurezza intelligente a livello industriale\\n- **Documentazione Tecnica** \u2014 Guide di integrazione API, utilizzo SDK, manuali di installazione\\n- **Approfondimenti di Settore** \u2014 Tendenze della sicurezza intelligente e analisi normative\\n\\n## Navigazione Rapida\\n\\n- Sfoglia [Prodotti e Soluzioni](/docs/tutorial-basics/create-a-page)\\n- Leggi [Chi Siamo](/docs/intro) per conoscere la storia di Heiman\\n- Visita il [Sito Ufficiale Heiman](https://www.heiman.com.cn)\\n\\nPer qualsiasi domanda, chiama la nostra hotline **400-8959-500** o contatta il supporto online."},{"id":"mdx-blog-post","metadata":{"permalink":"/heiman-wiki-public/it/blog/mdx-blog-post","source":"@site/i18n/it/docusaurus-plugin-content-blog/2021-08-01-mdx-blog-post.mdx","title":"Rivelatore di Fumo Intelligente Heiman con Protocollo Matter Ufficialmente Lanciato","description":"Il nuovo rivelatore di fumo intelligente con protocollo Matter di Heiman Technology, l\'HS1SA-M, \xe8 stato ufficialmente lanciato \u2014 uno dei primi rivelatori di fumo del settore a ricevere la certificazione Matter 1.2.","date":"2021-08-01T00:00:00.000Z","tags":[{"inline":false,"label":"Matter","permalink":"/heiman-wiki-public/it/blog/tags/matter","description":"Contenuti relativi al protocollo Matter"},{"inline":false,"label":"Antincendio Intelligente","permalink":"/heiman-wiki-public/it/blog/tags/smart-fire","description":"Prodotti e soluzioni antincendio intelligenti"}],"readingTime":0.7,"hasTruncateMarker":true,"authors":[{"name":"Heiman Technology","title":"Shenzhen Heiman Technology Co., Ltd.","url":"https://www.heiman.com.cn","page":{"permalink":"/heiman-wiki-public/it/blog/authors/heiman"},"socials":{"x":"https://x.com/heimantech","linkedin":"https://www.linkedin.com/in/heimantech/"},"imageURL":"https://www.heiman.com.cn/favicon.ico","key":"heiman"}],"frontMatter":{"slug":"mdx-blog-post","title":"Rivelatore di Fumo Intelligente Heiman con Protocollo Matter Ufficialmente Lanciato","authors":["heiman"],"tags":["matter","smart-fire"]},"unlisted":false,"prevItem":{"title":"Benvenuti nel Wiki di Heiman Technology","permalink":"/heiman-wiki-public/it/blog/welcome"},"nextItem":{"title":"Pietre Miliari di Heiman Technology","permalink":"/heiman-wiki-public/it/blog/long-blog-post"}},"content":"Il nuovo rivelatore di fumo intelligente con protocollo Matter di Heiman Technology, l\'HS1SA-M, \xe8 stato ufficialmente lanciato \u2014 uno dei primi rivelatori di fumo del settore a ricevere la certificazione Matter 1.2.\\n\\n{/* truncate */}\\n\\n:::tip\\n\\nL\'HS1SA-M supporta Apple HomeKit, Amazon Alexa, Google Home e Samsung SmartThings \u2014 i quattro principali ecosistemi smart home.\\n\\n:::\\n\\n## Caratteristiche Principali\\n\\n- **Certificato Matter 1.2** \u2014 Interoperabilit\xe0 cross-brand e cross-ecosistema\\n- **Rilevamento Fumo Fotoelettrico** \u2014 Risposta rapida a vari tipi di fumo da incendio\\n- **Allarme Vocale** \u2014 Opzioni multilingua, avvisi di pericolo chiari\\n- **Funzione Autotest** \u2014 Autocontrolli regolari per garantire il normale funzionamento\\n- **Notifica Remota** - Notifiche push in tempo reale sull\'APP del telefono\\n\\n## Compatibilit\xe0\\n\\nL\'HS1SA-M si integra perfettamente con le principali piattaforme smart home senza richiedere un gateway aggiuntivo \u2014 gestisci tutto direttamente dal tuo telefono.\\n\\nVisita la pagina [Prodotti](/docs/tutorial-basics/create-a-page) per saperne di pi\xf9."},{"id":"long-blog-post","metadata":{"permalink":"/heiman-wiki-public/it/blog/long-blog-post","source":"@site/i18n/it/docusaurus-plugin-content-blog/2019-05-29-long-blog-post.mdx","title":"Pietre Miliari di Heiman Technology","description":"Dalla sua fondazione nel 2005, Heiman Technology ha percorso oltre 20 anni di storia. Questo articolo ripercorre le tappe fondamentali di Heiman.","date":"2019-05-29T00:00:00.000Z","tags":[{"inline":false,"label":"Heiman Technology","permalink":"/heiman-wiki-public/it/blog/tags/heiman","description":"Notizie e aggiornamenti Heiman Technology"}],"readingTime":1.21,"hasTruncateMarker":true,"authors":[{"name":"Heiman Technology","title":"Shenzhen Heiman Technology Co., Ltd.","url":"https://www.heiman.com.cn","page":{"permalink":"/heiman-wiki-public/it/blog/authors/heiman"},"socials":{"x":"https://x.com/heimantech","linkedin":"https://www.linkedin.com/in/heimantech/"},"imageURL":"https://www.heiman.com.cn/favicon.ico","key":"heiman"}],"frontMatter":{"slug":"long-blog-post","title":"Pietre Miliari di Heiman Technology","authors":["heiman"],"tags":["heiman"]},"unlisted":false,"prevItem":{"title":"Rivelatore di Fumo Intelligente Heiman con Protocollo Matter Ufficialmente Lanciato","permalink":"/heiman-wiki-public/it/blog/mdx-blog-post"},"nextItem":{"title":"Heiman Technology Riconosciuta come Impresa Nazionale \\"Piccolo Gigante\\"","permalink":"/heiman-wiki-public/it/blog/first-blog-post"}},"content":"Dalla sua fondazione nel 2005, Heiman Technology ha percorso oltre 20 anni di storia. Questo articolo ripercorre le tappe fondamentali di Heiman.\\n\\n{/* truncate */}\\n\\n## 2005 - Fondazione dell\'Azienda\\n\\nViene ufficialmente fondata Shenzhen Heiman Technology Co., Ltd., entrando nel settore dei sensori di sicurezza.\\n\\n## 2006 - Inizio Internazionale\\n\\nNumerosi prodotti superano la certificazione CE dell\'UE e viene avviata una partnership con China Mobile.\\n\\n## 2011 - Rottura nelle Certificazioni Internazionali\\n\\nNumerosi prodotti ottengono le certificazioni EN54-7 ed EN14604 dell\'UE, raggiungendo standard qualitativi internazionali.\\n\\n## 2012 - Trasformazione Smart Home\\n\\nViene lanciato il progetto smart home, trasformando Heiman in un\'azienda specializzata in R&S, produzione e vendita di prodotti per la casa intelligente.\\n\\n## 2017 - Grandi Rotture\\n\\n- Sviluppato il primo rivelatore di fumo NB-IoT in Cina\\n- Vinti 2 Red Dot Design Award\\n- Superata la certificazione MFi, qualificati come produttore Apple\\n\\n## 2020 - Impulso di Capitale\\n\\nCompletato il finanziamento di Serie A con Shenzhen\u9AD8\u65B0\u6295 Group, riconosciuti come \\"PMI Specializzata e Nuova della Provincia del Guangdong\\".\\n\\n## 2022 - Riconoscimento Nazionale\\n\\nRiconosciuti come Impresa Nazionale Specializzata e Nuova \\"Piccolo Gigante\\". La serie K1 vince il Red Dot Design Award.\\n\\n## 2023 - Leadership negli Standard Internazionali\\n\\nIl laboratorio di prova Heiman supera ufficialmente la certificazione CNAS. I rivelatori di fumo e CO ottengono per primi la certificazione Matter 1.2.\\n\\n## 2024 - Oggi\\n\\nContinua l\'innovazione, approfondendo l\'impegno in Antincendio Intelligente, Sicurezza Gas Intelligente, Assistenza Anziani Intelligente e Sensori Intelligenti, fornendo prodotti e servizi di qualit\xe0 a clienti in oltre 100 paesi in tutto il mondo."},{"id":"first-blog-post","metadata":{"permalink":"/heiman-wiki-public/it/blog/first-blog-post","source":"@site/i18n/it/docusaurus-plugin-content-blog/2019-05-28-first-blog-post.mdx","title":"Heiman Technology Riconosciuta come Impresa Nazionale \\"Piccolo Gigante\\"","description":"Nel 2022, Heiman Technology \xe8 stata ufficialmente riconosciuta come Impresa Nazionale Specializzata e Nuova \\"Piccolo Gigante\\" per il suo profondo accumulo tecnico e l\'innovazione nel campo dei sensori intelligenti.","date":"2019-05-28T00:00:00.000Z","tags":[{"inline":false,"label":"Heiman Technology","permalink":"/heiman-wiki-public/it/blog/tags/heiman","description":"Notizie e aggiornamenti Heiman Technology"}],"readingTime":0.48,"hasTruncateMarker":true,"authors":[{"name":"Heiman Technology","title":"Shenzhen Heiman Technology Co., Ltd.","url":"https://www.heiman.com.cn","page":{"permalink":"/heiman-wiki-public/it/blog/authors/heiman"},"socials":{"x":"https://x.com/heimantech","linkedin":"https://www.linkedin.com/in/heimantech/"},"imageURL":"https://www.heiman.com.cn/favicon.ico","key":"heiman"}],"frontMatter":{"slug":"first-blog-post","title":"Heiman Technology Riconosciuta come Impresa Nazionale \\"Piccolo Gigante\\"","authors":["heiman"],"tags":["heiman"]},"unlisted":false,"prevItem":{"title":"Pietre Miliari di Heiman Technology","permalink":"/heiman-wiki-public/it/blog/long-blog-post"}},"content":"Nel 2022, Heiman Technology \xe8 stata ufficialmente riconosciuta come Impresa Nazionale Specializzata e Nuova \\"Piccolo Gigante\\" per il suo profondo accumulo tecnico e l\'innovazione nel campo dei sensori intelligenti.\\n\\n{/* truncate */}\\n\\nQuesto riconoscimento a livello nazionale afferma l\'eccellenza di Heiman in specializzazione, raffinatezza, differenziazione e innovazione. Heiman continuer\xe0 ad approfondire i suoi sforzi nei settori Antincendio Intelligente, Sicurezza Gas Intelligente, Assistenza Anziani Intelligente e Sensori Intelligenti, fornendo costantemente prodotti e servizi di alta qualit\xe0 ai clienti.\\n\\nHeiman aveva precedentemente ricevuto il riconoscimento come Impresa Nazionale ad Alta Tecnologia e PMI Specializzata e Nuova della Provincia del Guangdong."}]}}')}}]);